{
  "name": "Agency Creator",
  "mission": "To guide human domain experts through a structured design process that produces coherent, validated Agency artifacts — in both JSON and Markdown format — ready for deployment on the CodeVald platform.",
  "vision": "Every agency created on the CodeVald platform is coherently designed, consistently structured, and traceable from mission to work item — eliminating ambiguity and accelerating delivery from day one.",
  "status": "AGENCY_LIFECYCLE_DRAFT",
  "goals": [
    {
      "title": "Elicit Domain Knowledge",
      "description": "Capture coherent requirements from human domain experts through structured Q&A to fully define the agency's purpose, roles, and workflows.",
      "ordinality": 1
    },
    {
      "title": "Design Coherent Agency Structure",
      "description": "Translate elicited requirements into a logically consistent agency design — with aligned Goals, Workflows, Work Items, and RACI assignments.",
      "ordinality": 2
    },
    {
      "title": "Produce Validated JSON Artifact",
      "description": "Generate a structurally correct agency.json that passes all data model rules before being written to disk.",
      "ordinality": 3
    },
    {
      "title": "Produce Markdown Documentation",
      "description": "Generate a human-readable Markdown document alongside the JSON, describing the agency's design for traceability and review.",
      "ordinality": 4
    }
  ],
  "workflows": [
    {
      "name": "Domain Elicitation",
      "work_items": [
        {
          "title": "Initiate Session",
          "description": "Open the design session; capture the agency's one-sentence purpose and confirm the agency name.",
          "order": 1,
          "parallel": false,
          "goal_ids": [
            "Elicit Domain Knowledge"
          ],
          "assignments": [
            {
              "role": "agency_designer",
              "raci": "R"
            },
            {
              "role": "admin",
              "raci": "A"
            },
            {
              "role": "domain_expert",
              "raci": "C"
            }
          ]
        },
        {
          "title": "Refine Mission & Vision",
          "description": "Using the stated purpose as a seed, propose a draft Mission and Vision for the domain expert to confirm, refine, or reject.",
          "order": 2,
          "parallel": false,
          "goal_ids": [
            "Elicit Domain Knowledge",
            "Design Coherent Agency Structure"
          ],
          "assignments": [
            {
              "role": "agency_designer",
              "raci": "R"
            },
            {
              "role": "admin",
              "raci": "A"
            },
            {
              "role": "domain_expert",
              "raci": "C"
            }
          ]
        },
        {
          "title": "Elicit Goals & Ordinality",
          "description": "Identify all strategic Goals and assign priority order through structured Q&A.",
          "order": 3,
          "parallel": false,
          "goal_ids": [
            "Elicit Domain Knowledge",
            "Design Coherent Agency Structure"
          ],
          "assignments": [
            {
              "role": "agency_designer",
              "raci": "R"
            },
            {
              "role": "admin",
              "raci": "A"
            },
            {
              "role": "domain_expert",
              "raci": "C"
            }
          ]
        },
        {
          "title": "Elicit Roles & Actor Types",
          "description": "Define all custom roles beyond admin/super_admin, and specify the actor_type (human, ai, or either) for each.",
          "order": 4,
          "parallel": false,
          "goal_ids": [
            "Elicit Domain Knowledge",
            "Design Coherent Agency Structure"
          ],
          "assignments": [
            {
              "role": "agency_designer",
              "raci": "R"
            },
            {
              "role": "admin",
              "raci": "A"
            },
            {
              "role": "domain_expert",
              "raci": "C"
            }
          ]
        },
        {
          "title": "Elicit Workflows & Work Items",
          "description": "Define all Workflows, Work Items, execution order, parallelism, goal references, and RACI assignments.",
          "order": 5,
          "parallel": false,
          "goal_ids": [
            "Elicit Domain Knowledge",
            "Design Coherent Agency Structure"
          ],
          "assignments": [
            {
              "role": "agency_designer",
              "raci": "R"
            },
            {
              "role": "admin",
              "raci": "A"
            },
            {
              "role": "domain_expert",
              "raci": "C"
            }
          ]
        },
        {
          "title": "Validate Design Completeness",
          "description": "Verify all stop conditions are cleared — every work item has assignments, all goal_ids resolve to valid Goals, and ordinality values are unique.",
          "order": 6,
          "parallel": false,
          "goal_ids": [
            "Elicit Domain Knowledge",
            "Design Coherent Agency Structure"
          ],
          "assignments": [
            {
              "role": "agency_designer",
              "raci": "R"
            },
            {
              "role": "admin",
              "raci": "A"
            },
            {
              "role": "domain_expert",
              "raci": "C"
            }
          ]
        }
      ]
    },
    {
      "name": "Artifact Production",
      "work_items": [
        {
          "title": "Generate agency.json",
          "description": "Produce the validated agency.json file matching the data model exactly, with status set to draft.",
          "order": 1,
          "parallel": true,
          "goal_ids": [
            "Produce Validated JSON Artifact"
          ],
          "assignments": [
            {
              "role": "agency_designer",
              "raci": "R"
            },
            {
              "role": "admin",
              "raci": "A"
            },
            {
              "role": "agency_reviewer",
              "raci": "C"
            },
            {
              "role": "domain_expert",
              "raci": "I"
            }
          ]
        },
        {
          "title": "Generate Markdown Documentation",
          "description": "Produce the human-readable Markdown companion document describing the agency's mission, vision, goals, roles, workflows, and work items.",
          "order": 1,
          "parallel": true,
          "goal_ids": [
            "Produce Markdown Documentation"
          ],
          "assignments": [
            {
              "role": "agency_designer",
              "raci": "R"
            },
            {
              "role": "admin",
              "raci": "A"
            },
            {
              "role": "agency_reviewer",
              "raci": "C"
            },
            {
              "role": "domain_expert",
              "raci": "I"
            }
          ]
        },
        {
          "title": "Review & Sign-off",
          "description": "Reviewer checks both artifacts for correctness, coherence, and full data model compliance before the agency is persisted.",
          "order": 2,
          "parallel": false,
          "goal_ids": [
            "Produce Validated JSON Artifact",
            "Produce Markdown Documentation"
          ],
          "assignments": [
            {
              "role": "agency_reviewer",
              "raci": "R"
            },
            {
              "role": "admin",
              "raci": "A"
            },
            {
              "role": "domain_expert",
              "raci": "I"
            }
          ]
        }
      ]
    }
  ],
